#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,a[N],l[N],r[N];
long long s[N],ans;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		s[i]=s[i-1]+a[i];
	}
	stack<int> sta;
	for(int i=1;i<=n;i++){
		while(sta.size() && a[sta.top()]>a[i])
			r[sta.top()]=i,sta.pop();
		sta.push(i);
	}
	while(sta.size())
		r[sta.top()]=n+1,sta.pop();
	for(int i=n;i;i--){
		while(sta.size() && a[sta.top()]>a[i])
			l[sta.top()]=i,sta.pop();
		sta.push(i);
	}
	while(sta.size())
		l[sta.top()]=0,sta.pop();
	for(int i=1;i<=n;i++)
		ans=max(ans,(s[r[i]-1]-s[l[i]])*a[i]);
	printf("%lld",ans);
	return 0;
}
